import "./index-first.css";

function IndexFirst(){



    return(
        <div className="container">
            <img src="Burguer-cuadrada.png" alt="Burguer"/>
            <div className="promos">
                <h1>BURGUERS&CHIPS</h1>
                <p>Descubre BURGUERS&CHIPS, donde las hamburguesas son obras maestras y las papas fritas son adictivas. En un ambiente moderno y acogedor, cada hamburguesa se prepara con ingredientes frescos y de alta calidad. Las papas fritas son crujientes por fuera y suaves por dentro, el complemento perfecto. El servicio es excepcional, con un personal amable y atento que garantiza una experiencia memorable. BURGUERS&CHIPS es más que una hamburguesería; es un destino gastronómico imprescindible para los amantes de la buena comida. ¡Ven y descubre por qué es el favorito de la ciudad!</p>
            
            </div>
        </div>
    );
};

export default IndexFirst;
